
import React, { useEffect, useState } from "react";
import { Recycle } from "lucide-react";
import AnimatedContainer from "./AnimatedContainer";

const Navbar: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      const isScrolled = window.scrollY > 10;
      if (isScrolled !== scrolled) {
        setScrolled(isScrolled);
      }
    };

    window.addEventListener("scroll", handleScroll);
    return () => {
      window.removeEventListener("scroll", handleScroll);
    };
  }, [scrolled]);

  return (
    <header
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        scrolled
          ? "bg-white/80 backdrop-blur-md shadow-sm"
          : "bg-transparent"
      }`}
    >
      <div className="container mx-auto px-4 h-16 flex items-center justify-between">
        <AnimatedContainer animationType="slide-down">
          <div className="flex items-center gap-2">
            <Recycle className="h-6 w-6 text-primary" />
            <h1 className="text-xl font-medium">WasteWise AI</h1>
          </div>
        </AnimatedContainer>

        <AnimatedContainer animationType="slide-down" delay={100}>
          <nav className="flex items-center space-x-1">
            <a
              href="#"
              className="px-3 py-2 text-sm rounded-md transition-colors hover:bg-secondary"
            >
              Home
            </a>
            <a
              href="#about"
              className="px-3 py-2 text-sm rounded-md transition-colors hover:bg-secondary"
            >
              About
            </a>
            <a
              href="#categories"
              className="px-3 py-2 text-sm rounded-md transition-colors hover:bg-secondary"
            >
              Categories
            </a>
          </nav>
        </AnimatedContainer>
      </div>
    </header>
  );
};

export default Navbar;
